  ['red', '#d20f39', '#f38ba8'],
  ['maroon', '#e64553', '#eba0ac'],
  ['peach', '#fe640b', '#fab387'],
  ['yellow', '#df8e1d', '#f9e2af'],
  ['green', '#40a02b', '#a6e3a1'],
  ['teal', '#179299', '#94e2d5'],
  ['sky', '#04a5e5', '#89dceb'],
  ['sapphire', '#209fb5', '#74c7ec'],
  ['blue', '#1e66f5', '#89b4fa'],
  ['lavender', '#7287fd', '#b4befe'],
  ['text', '#4c4f69', '#cdd6f4'],
  ['subtext1', '#5c5f77', '#bac2de'],
  ['subtext0', '#6c6f85', '#a6adc8'],
