    classes: 'bg-mnl-warning text-[#11111b]',
    note: 'Attention states',
  },
  {
    label: 'Error',
    classes: 'bg-mnl-error text-[#11111b]',
    note: 'Destructive and error states',
  },
  {
    label: 'Info',
