      <div class="flex min-h-dvh min-w-0 flex-1 flex-col">
        <div
          #contentViewport
          class="flex-1 overflow-y-auto pb-24 lg:pb-0"
          data-testid="mnl-page-shell-content"
        >
          <div
            class="mx-auto w-full max-w-screen-2xl px-4 py-6 sm:px-6 lg:px-8"
